VALUES
  ('fire-eq-tech-moex-02490', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法」之規定，下列有關室外儲槽場所之敘述 何者錯誤？', '["儲存閃火點未達攝氏二十一度之六類物品，其容量四十公秉以上者，儲槽之周圍保留空地應在十公尺 以上", "儲存閃火點未達攝氏六十度之六類物品：固定式儲槽直徑未達四十五公尺者，相鄰儲槽間之距離為相 鄰二座儲槽直徑和之六分之一，最低為九十公分", "儲存二硫化碳之儲槽，槽壁厚度不得小於十公分", "幫浦設備與儲槽之距離不得小於儲槽保留空地寬度之三分之一"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02491', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「各類場所消防安全設備檢修及申報作業基準」，進行水成膜泡沫滅火藥劑發泡倍率試驗及 25%還 原時間測定時，假設泡沫試料之淨重為200公克，則其發泡倍率X倍，25%還原時間為Y分鐘，請問前 述X，Y為何？', '["5，2.5", "5，3", "7，1.5", "7，2"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02492', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '某一建築物地上層有25層、地下層有5層，依照「建築技術規則」之規定，有關其主要構造的樑、柱、 承重牆壁及樓地板之防火時效，下列何者錯誤？', '["地上第24層的承重牆壁至少應1小時以上", "地上第18層的樑至少應2小時以上", "地上第8層的柱至少應2小時以上", "地下第3層的樓地板至少應2小時以上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02493', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「消防幫浦加壓送水裝置等及配管摩擦損失計算基準」之規定，下列敘述何者錯誤？', '["防止水溫上升用之排水管內之流水量，當幫浦在全閉狀態下連續運轉時，不使幫浦內部水溫值升高攝 氏二十度以上", "呼水裝置應有100公升以上之有效儲存量", "啟動用壓力槽容量應有 100  公升以上", "幫浦本體必須能耐最高水壓之 1.5  倍以上，且加壓3分鐘後，各部位仍無洩漏現象才算合格"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02494', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「消防法」規定，下列何者發現或獲知公共危險物品、高壓氣體等，顯著有發生火災、爆炸之虞時， 得劃定警戒區域，限制人車進入，強制疏散，並得限制或禁止該區使用火源？', '["消防指揮人員", "直轄市、縣（市）消防機關", "當地警察分區或派出所", "直轄市、縣（市）政府"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02495', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備設置標準」規定，公共危險物品等場所設置室內消防栓時，任一樓層內，全 部室內消防栓同時使用時，各消防栓瞄子放水壓力在每平方公分多少公斤以上？', '["1.7", "2.5", "3.5", "4.5"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02496', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「原有合法建築物防火避難設施及消防設備改善辦法」之規定，合法建築物十一層以上之樓層，其室 內牆面及天花板（包括底材）均以耐燃一級材料裝修者，得按每多少平方公尺範圍內實施面積區劃？', '["100", "300", "500", "1000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02497', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法」，有關液化石油氣之規定，下列何者 錯誤？', '["販賣場所儲放之液化石油氣，總儲氣量不得超過130公斤", "儲存場所僅供一家處理場所使用之面積，不得少於10平方公尺", "液化石油氣備用量，供營業使用者，不得超過80公斤", "液化石油氣備用量，供家庭使用者，不得超過40公斤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02498', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法」之規定，某一可燃性高壓氣體儲存場 所的儲存面積為 9 平方公尺，試問其外牆設施之外側，與第一類保護物及第二類保護物之安全距離，分 別為X公尺及Y公尺以上，請問前述X，Y為何？', '["12.6，8.4", "22.5，15", "11.25，7.5", "13.5，9"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02499', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「各類場所消防安全設備檢修及申報作業基準」，某一光電式局限型第 2 種蓄積型偵煙探測器，其 標稱蓄積時間為20秒，現以加煙試驗器進行火災動作試驗時，其動作時間應在多少時間以內，方為正常？', '["60秒", "80秒", "85秒", "90秒"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
